// AUTO-GENERATED by workflow — art. Do not hand-edit; re-run integrate.mjs.
//
// ENHANCED EDITION (art_v2): drop-in replacement for the generated WEAPON icons.
// Same names / sizes / anchors / imports / exports — only the draw bodies grew up.
//   • Top-left light source, 3-4 tonal steps per material + a specular glint.
//   • Cool weapon flair: blade gleam, energy edges, glowing runes, neon trims,
//     muzzle glow, beam streaks, frost/venom/flame VFX cores.
//   • p.glow / p.star4 / p.sparkle / p.rimLight used for that "anime pop".
// defineIcon() auto-draws a rounded panel + outline, so each draw fn only
// renders the weapon symbol (and now its energy/VFX on top of the plaque).
import { defineSprite, defineAnim, Painter } from '../../engine/sprites.js';
