// ── tiny shared weapon helpers (additive) ──────────────────────────────────
// brushed-metal barrel: core + top sheen line + bottom shade + edge glint
function barrel(p, x, y, w, h, core = P.iron, hi = P.steelL) {
  p.gradV(x, y, w, h, lighten(core, 0.18), darken(core, 0.22));
  p.hline(x, x + w - 1, y, hi);            // top sheen
  p.hline(x, x + w - 1, y + h - 1, darken(core, 0.35));
  p.px(x, y, lighten(hi, 0.25));           // top-left glint
}
// muzzle flash / energy mouth at the barrel tip
function muzzle(p, x, y, col, coreCol = P.white) {
  p.glow(x, y, 2.4, col, 0.6, 4);
  p.px(x, y, coreCol);
  p.sparkle(x, y, lighten(col, 0.35), 1);
}
// a small glowing rune dot (cyber/arcane trim)
function rune(p, x, y, col) {
  p.glow(x, y, 1.4, col, 0.5, 3);
  p.px(x, y, lighten(col, 0.4));
}

// equipment_weapons icons. defineIcon auto-draws a rounded panel + outline,
// so each draw fn only renders the weapon symbol.

// machine gun: stubby barrel + ammo belt, hot muzzle + glowing tracer rounds
defineIcon('equip_g_machinegun', P.gray1, (p) => {
  // receiver body
  p.gradV(3, 6, 8, 3, lighten(P.iron, 0.16), darken(P.iron, 0.2));
  p.hline(3, 10, 6, P.gray3);
  p.hline(3, 10, 8, darken(P.iron, 0.32));
  // barrel block + vented heat shroud
  barrel(p, 11, 6, 3, 3, P.steel, P.steelL);
  p.px(13, 7, P.steelL);
  p.px(12, 6, P.glint);
  // grip
  p.gradV(5, 11, 2, 3, P.woodL, P.woodD);
  p.px(5, 11, lighten(P.woodL, 0.2));
  // ammo belt — glowing brass rounds
  for (let i = 0; i < 3; i++) {
    p.px(3 + i * 2, 4, P.goldL);
    p.px(3 + i * 2, 5, P.goldD);
  }
  rune(p, 4, 9, P.neon);                 // cyber trim on the body
  muzzle(p, 14, 7, P.emberL, P.white);   // hot muzzle flash
  p.rimLight(P.rim, 0.5, -1, -1);
});

